// // This module generates power supply signals for digital circuits. On each negative edge of the input clock, it outputs a logic low (0) for VPWR and VPB, and a logic high (1) for VGND and VNB.
module top_module(
    input wire clk,
    output reg VPWR,
    output reg VGND,
    output reg VPB,
    output reg VNB
);always @(posedge clk) begin
        VPWR <= 1;
        VGND <= 0;
        VPB <= 1;
        VNB <= 0;
    end

endmodule
